func TestSelectStoreCoverageBaselineSnapshot_DefaultsToPreviousSnapshot(t *testing.T) {
	db := openCoverageDiffTestStore(t)
	writeCoverageDiffSnapshot(t, db, "market", "2026-05-01T00:00:00Z", 1)
	writeCoverageDiffSnapshot(t, db, "market", "2026-05-10T00:00:00Z", 2)
	writeCoverageDiffSnapshot(t, db, "market", "2026-05-20T00:00:00Z", 3)

	snaps, err := listStoreSnapshots(db, "market")
	if err != nil {
		t.Fatalf("list snapshots: %v", err)
	}
	baselineID := selectStoreCoverageBaselineSnapshot(db, snaps, time.Time{})
	if baselineID != "market/all/2026-05-10T00:00:00Z" {
		t.Fatalf("baselineID = %q, want previous snapshot", baselineID)
	}
	baselineItems, _, err := loadStoreSnapshot(db, baselineID)
	if err != nil {
		t.Fatalf("load baseline: %v", err)
	}
	latestItems, _, err := loadStoreSnapshot(db, snaps[len(snaps)-1])
	if err != nil {
		t.Fatalf("load latest: %v", err)
	}
	if got := len(latestItems) - len(baselineItems); got != 1 {
		t.Fatalf("default change = %d, want 1", got)
	}
}

func TestSelectStoreCoverageBaselineSnapshot_UsesSinceCutoff(t *testing.T) {
	db := openCoverageDiffTestStore(t)
	writeCoverageDiffSnapshot(t, db, "market", "2026-05-01T00:00:00Z", 1)
	writeCoverageDiffSnapshot(t, db, "market", "2026-05-10T00:00:00Z", 2)
	writeCoverageDiffSnapshot(t, db, "market", "2026-05-20T00:00:00Z", 3)

	snaps, err := listStoreSnapshots(db, "market")
	if err != nil {
		t.Fatalf("list snapshots: %v", err)
	}
	sinceT, err := time.Parse("2006-01-02", "2026-05-05")
	if err != nil {
		t.Fatalf("parse since: %v", err)
	}
	baselineID := selectStoreCoverageBaselineSnapshot(db, snaps, sinceT)
	if baselineID != "market/all/2026-05-01T00:00:00Z" {
		t.Fatalf("baselineID = %q, want latest snapshot before since", baselineID)
	}
}

func TestStoresCoverageDiffRejectsInvalidSince(t *testing.T) {
	cmd := newStoresCoverageDiffCmd(&rootFlags{})
	cmd.SilenceUsage = true
	cmd.SetArgs([]string{"--since", "2026/05/01"})

	err := cmd.Execute()
	if err == nil {
		t.Fatal("expected invalid --since to fail")
	}
	if !strings.Contains(err.Error(), "--since must be YYYY-MM-DD") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func openCoverageDiffTestStore(t *testing.T) *store.Store {
	t.Helper()
	db, err := store.Open(filepath.Join(t.TempDir(), "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	t.Cleanup(func() {
		if err := db.Close(); err != nil {
			t.Fatalf("close store: %v", err)
		}
	})
	return db
}

func writeCoverageDiffSnapshot(t *testing.T, db *store.Store, storeType, takenAt string, count int) {
	t.Helper()
	items := make([]rappi.Store, 0, count)
	for i := 0; i < count; i++ {
		items = append(items, rappi.Store{ID: fmt.Sprintf("%s-%d", storeType, i)})
	}
	raw, err := json.Marshal(map[string]any{
		"store_type": storeType,
		"city":       "all",
		"taken_at":   takenAt,
		"items":      items,
	})
	if err != nil {
		t.Fatalf("marshal snapshot: %v", err)
	}
	if err := db.Upsert("store_snapshot", storeType+"/all/"+takenAt, raw); err != nil {
		t.Fatalf("upsert snapshot: %v", err)
	}
}
